patch:
diff --git a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
index 45330e548bc29..458459e854233 100644
--- a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
+++ b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
@@ -949,6 +949,11 @@ bool VectorCombine::foldBitOpOfCastops(Instruction &I) {
   if (auto *NewBinOp = dyn_cast<BinaryOperator>(NewOp))
     NewBinOp->copyIRFlags(BinOp);

+  // disjoint flag can't be preserved through a bitcast
+  if (CastOpcode == Instruction::BitCast)
+    if (auto *Disjoint = dyn_cast<PossiblyDisjointInst>(NewOp))
+      Disjoint->setIsDisjoint(false);
+
   Worklist.pushValue(NewOp);

   // Create the cast operation directly to ensure we get a new instruction
@@ -1052,6 +1057,11 @@ bool VectorCombine::foldBitOpOfCastConstant(Instruction &I) {
   if (auto *NewBinOp = dyn_cast<BinaryOperator>(NewOp))
     NewBinOp->copyIRFlags(&I);

+  // disjoint flag can't be preserved through a bitcast
+  if (CastOpcode == Instruction::BitCast)
+    if (auto *Disjoint = dyn_cast<PossiblyDisjointInst>(NewOp))
+      Disjoint->setIsDisjoint(false);
+
   Worklist.pushValue(NewOp);

   // Create the cast operation directly to ensure we get a new instruction

tests.test_body:
define i16 @or_bitcast_v16i1_to_i16(<16 x i1> %a, <16 x i1> %b) {
  %bc1 = bitcast <16 x i1> %a to i16
  %bc2 = bitcast <16 x i1> %b to i16
  %or = or i16 %bc1, %bc2
  ret i16 %or
}

define <2 x i32> @issue199783_1(i64 %x) {
  %cast = bitcast i64 %x to <2 x i32>
  %or_disjoint = or disjoint <2 x i32> %cast, splat (i32 1)
  ret <2 x i32> %or_disjoint
}

define <2 x i32> @issue199783_2(i64 %x, i64 %y) {
  %cast_x = bitcast i64 %x to <2 x i32>
  %cast_y = bitcast i64 %y to <2 x i32>
  %or_disjoint = or disjoint <2 x i32> %cast_x, %cast_y
  ret <2 x i32> %or_disjoint
}
